class Solution:
    def canPartition(self, nums):
        total = sum(nums)
        if total % 2:
            return False
        target = total // 2
        from functools import lru_cache
        nums = tuple(nums)
        import sys
        sys.setrecursionlimit(10000)
        @lru_cache(maxsize=None)
        def rec(i, rem):
            if rem == 0:
                return True
            if i >= len(nums) or rem < 0:
                return False
            return rec(i + 1, rem - nums[i]) or rec(i + 1, rem)
        return rec(0, target)

