class Solution:
    def canPartition(self, nums):
        total = sum(nums)
        if total % 2:
            return False
        target = total // 2
        reachable = [False] * (target + 1)
        reachable[0] = True
        for num in nums:
            for t in range(target, num - 1, -1):
                if reachable[t - num]:
                    reachable[t] = True
        return reachable[target]

